const e=require("fs"),r=e.readdirSync(".").filter(e=>e.endsWith(".html"));let c=0;r.forEach(r=>{let l=e.readFileSync(r,"utf8");!l.includes("firebasestorage.googleapis.com")&&l.includes('<link rel="preconnect" href="https://res.cloudinary.com">')&&(l=l.replace('<link rel="preconnect" href="https://res.cloudinary.com">','<link rel="preconnect" href="https://res.cloudinary.com"><link rel="preconnect" href="https://firebasestorage.googleapis.com">'),e.writeFileSync(r,l),c++)}),console.log("Updated "+c+" HTML files");